package taskengine

import (
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

func TestValidateOverdueActionRule(t *testing.T) {
	allRecurrenceTypes := []dbgen.RecurrenceType{
		dbgen.RecurrenceTypeOneOff,
		dbgen.RecurrenceTypeCompletionBased,
		dbgen.RecurrenceTypeFixedNonAccumulating,
		dbgen.RecurrenceTypeFixedAccumulating,
		dbgen.RecurrenceTypeOnDependency,
	}

	// Helper to build a matrix of cases that apply to every recurrence type.
	withAllRecurrenceTypes := func(name string, action dbgen.OverdueAction, statusName pgtype.Text, hasDue bool, wantErr bool, errContains string) []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	} {
		var cases []struct {
			name           string
			afterDays      pgtype.Int4
			action         dbgen.NullOverdueAction
			statusName     pgtype.Text
			recurrenceType dbgen.RecurrenceType
			hasDue         bool
			wantErr        bool
			errContains    string
		}
		for _, rt := range allRecurrenceTypes {
			cases = append(cases, struct {
				name           string
				afterDays      pgtype.Int4
				action         dbgen.NullOverdueAction
				statusName     pgtype.Text
				recurrenceType dbgen.RecurrenceType
				hasDue         bool
				wantErr        bool
				errContains    string
			}{
				name:           name + " on " + rt,
				action:         nullOverdueAction(action),
				statusName:     statusName,
				recurrenceType: rt,
				hasDue:         hasDue,
				wantErr:        wantErr,
				errContains:    errContains,
			})
		}
		return cases
	}

	var tests []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}

	// No rule is always valid, regardless of recurrence type or due date.
	for _, rt := range allRecurrenceTypes {
		tests = append(tests, struct {
			name           string
			afterDays      pgtype.Int4
			action         dbgen.NullOverdueAction
			statusName     pgtype.Text
			recurrenceType dbgen.RecurrenceType
			hasDue         bool
			wantErr        bool
			errContains    string
		}{
			name:           "nil rule on " + rt,
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: rt,
			hasDue:         false,
			wantErr:        false,
		})
	}

	// Every action requires a due date.
	tests = append(tests, withAllRecurrenceTypes(
		"rule requires due date",
		dbgen.OverdueActionClearDueDate,
		pgtype.Text{},
		false,
		true,
		"requires a due date",
	)...)

	// set_status requires a status name.
	tests = append(tests, withAllRecurrenceTypes(
		"set_status without status",
		dbgen.OverdueActionSetStatus,
		pgtype.Text{Valid: false},
		true,
		true,
		"status is required",
	)...)

	// set_status is valid on every task type with a due date.
	tests = append(tests, withAllRecurrenceTypes(
		"set_status with status",
		dbgen.OverdueActionSetStatus,
		pgtype.Text{String: "done", Valid: true},
		true,
		false,
		"",
	)...)

	// clear_due_date is valid on every task type with a due date.
	tests = append(tests, withAllRecurrenceTypes(
		"clear_due_date",
		dbgen.OverdueActionClearDueDate,
		pgtype.Text{},
		true,
		false,
		"",
	)...)

	// advance_recurrence is valid only on scheduled (non-accumulating) recurrence types.
	for _, rt := range allRecurrenceTypes {
		wantErr := rt != dbgen.RecurrenceTypeCompletionBased && rt != dbgen.RecurrenceTypeFixedNonAccumulating
		errContains := ""
		if rt == dbgen.RecurrenceTypeFixedAccumulating {
			errContains = "not supported on fixed_accumulating"
		} else if wantErr {
			errContains = "only valid on tasks with a scheduled recurrence"
		}
		tests = append(tests, struct {
			name           string
			afterDays      pgtype.Int4
			action         dbgen.NullOverdueAction
			statusName     pgtype.Text
			recurrenceType dbgen.RecurrenceType
			hasDue         bool
			wantErr        bool
			errContains    string
		}{
			name:           "advance_recurrence on " + rt,
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: rt,
			hasDue:         true,
			wantErr:        wantErr,
			errContains:    errContains,
		})
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}
}

